235	    private static string? ValidateStatusTransition(
236	        string currentStatus, string newStatus, string currentDiId, string? requestDiId,
237	        string? humanDecisionPath)
238	    {
239	        var isNewDi = requestDiId is not null &&
240	                      !string.Equals(requestDiId, currentDiId, StringComparison.OrdinalIgnoreCase);
