266	            return $"status 전이 {currentStatus} → {newStatus}는 허용되지 않습니다(허용: {allowedStr})";
267	        }
268	
269	        return null;
270	    }
271	
272	    // outputs/gates/<taskId>.gate.json 형식·gateVerdict·failureCount·taskId 일치·stale 여부를 검증한다.
273	    // targetDiId: completed 전이 대상 diId. gate.taskId와 일치해야 한다.
274	    // 대응 규칙: gate.taskId == 요청의 diId(있으면) 또는 현재 WORKSTATE.diId.
275	    // stale 판정: gate.createdAt 날짜 < WORKSTATE.updatedAt 날짜이면 오래된 증거로 거부한다.
276	    private static string? ValidateVerdict(string? verdictPath, string targetDiId, string workstateUpdatedAt)
277	    {
278	        if (string.IsNullOrWhiteSpace(verdictPath))
279	            return "status=completed 전이에는 --verdict 파일이 필요합니다";
280	
281	        // 경로 형식: outputs/gates/<taskId>.gate.json이어야 한다(다른 경로 거부).
282	        var normalized = verdictPath.Replace('\\', '/');
283	        var fileName = Path.GetFileName(normalized);
284	        if (!fileName.EndsWith(".gate.json", StringComparison.OrdinalIgnoreCase))
285	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
286	
287	        var dirPart = Path.GetDirectoryName(normalized)?.Replace('\\', '/') ?? "";
288	        if (!dirPart.EndsWith("outputs/gates", StringComparison.OrdinalIgnoreCase))
289	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
290	
291	        if (!File.Exists(verdictPath))
292	            return $"verdict file not found: {verdictPath}";
293	
294	        var gateJson = JsonNode.Parse(File.ReadAllText(verdictPath))?.AsObject();
295	        if (gateJson is null) return "gate JSON이 유효하지 않습니다";
296	
297	        var gateVerdict = gateJson["gateVerdict"]?.ToString();
298	        if (!string.Equals(gateVerdict, "PASS", StringComparison.OrdinalIgnoreCase))
299	            return $"gate verdict가 PASS가 아닙니다(gateVerdict={gateVerdict ?? "null"})";
300	
301	        var failureCount = gateJson["failureCount"]?.GetValue<int>() ?? -1;
302	        if (failureCount != 0)
303	            return $"gate failureCount가 0이 아닙니다(failureCount={failureCount})";
304	
305	        var gateTaskId = gateJson["taskId"]?.ToString();
306	        if (!string.Equals(gateTaskId, targetDiId, StringComparison.OrdinalIgnoreCase))
307	            return $"gate taskId({gateTaskId ?? "null"})가 전이 대상 DI({targetDiId})와 일치하지 않습니다";
308	
309	        // stale 검사: gate 생성일이 WORKSTATE updatedAt 날짜보다 이전이면 오래된 증거다.
310	        var createdAtStr = gateJson["createdAt"]?.ToString();
311	        if (createdAtStr is not null &&
312	            DateTimeOffset.TryParse(createdAtStr, out var createdAt) &&
313	            DateTime.TryParse(workstateUpdatedAt, out var wsUpdated) &&
314	            createdAt.Date < wsUpdated.Date)
315	        {
316	            return $"gate 증거가 WORKSTATE updatedAt({workstateUpdatedAt})보다 오래됐습니다(gate createdAt={createdAt:yyyy-MM-dd})";
317	        }
318	
319	        return null;
320	    }
321	
322	    // human-decision 파일이 approved=true인지 검증한다. context는 오류 메시지에 포함된다.
323	    private static string? ValidateHumanDecision(string? decPath, string context)
324	    {
325	        if (string.IsNullOrWhiteSpace(decPath))
326	            return $"{context}에는 --human-decision 파일이 필요합니다";
327	        if (!File.Exists(decPath))
328	            return $"human-decision file not found: {decPath}";
329	        var d = JsonNode.Parse(File.ReadAllText(decPath))?.AsObject();
330	        if (d is null) return "human-decision JSON이 유효하지 않습니다";
331	        var approved = d["approved"]?.GetValue<bool>() ?? false;
332	        return !approved ? $"{context}가 사람에게 승인되지 않았습니다(approved={approved})" : null;
333	    }
334	
335	    // request 필드를 current WORKSTATE에 병합해 candidate를 만들고 appliedTransitions에 기록한다.
336	    private static JsonObject BuildCandidate(JsonObject current, JsonObject request, ApplierOptions opts)
337	    {
338	        var candidate = JsonNode.Parse(current.ToJsonString(WriteOptions))!.AsObject()!;
339	
340	        foreach (var key in new[] { "phaseId", "wpId", "diId", "status", "blockers", "nextActions", "updatedBy", "notes" })
341	        {
342	            if (request[key] is JsonNode node)
343	                candidate[key] = node.DeepClone();
344	        }
345	
346	        candidate["updatedAt"] = DateTime.UtcNow.ToString("yyyy-MM-dd");
347	
348	        if (candidate["appliedTransitions"] is not JsonArray applied)
349	        {
350	            applied = new JsonArray();
351	            candidate["appliedTransitions"] = applied;
352	        }
353	
354	        applied.Add(new JsonObject
355	        {
356	            ["id"] = opts.TransitionId,
357	            ["appliedAt"] = DateTime.UtcNow.ToString("o"),
358	        });
359	
360	        return candidate;
361	    }
362	
363	    // candidate WORKSTATE의 사후 조건(status enum, blocked→blockers, non-terminal→nextActions, canonical ID 패턴, WP-REGISTRY 등록 여부)을 검증한다.
364	    private static string? ValidateCandidate(JsonObject candidate, string root)
365	    {
366	        var status = candidate["status"]?.ToString() ?? "";
367	        if (!ValidStatuses.Contains(status))
368	            return $"candidate status '{status}'가 유효하지 않습니다";
369	
370	        var blockers = candidate["blockers"] as JsonArray;
371	        if (string.Equals(status, "blocked", StringComparison.OrdinalIgnoreCase) && (blockers is null || blockers.Count == 0))
372	            return "candidate: status=blocked인데 blockers가 비어있습니다";
373	
374	        var nextActions = candidate["nextActions"] as JsonArray;
375	        if (NextActionsRequired.Contains(status) && (nextActions is null || nextActions.Count == 0))
376	            return $"candidate: status={status}인데 nextActions가 비어있습니다";
377	
378	        // canonical 패턴 검사 — 정지 상태(at rest)에서도 강제한다(요청에 없어 상속된 값 포함).
379	        if (candidate["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
380	            return $"candidate phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
381	
382	        if (candidate["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
383	            return $"candidate wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
384	
385	        if (candidate["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
386	            return $"candidate diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
387	
388	        // WP-REGISTRY 검사 — wpId가 등록된 WP인지 확인한다.
389	        var wpId = candidate["wpId"]?.ToString();
390	        if (!string.IsNullOrWhiteSpace(wpId))
391	        {
392	            var registryErr = ValidateWpRegistry(root, wpId);
393	            if (registryErr is not null) return registryErr;
394	        }
395	
396	        return null;
397	    }
398	
399	    // wpId가 WP-REGISTRY.json에 등록되어 있는지 검사한다. 없으면 오류 메시지를 반환한다.
400	    private static string? ValidateWpRegistry(string root, string wpId)
401	    {
402	        var registryPath = Path.Combine(root, "docs", "handoff", "WP-REGISTRY.json");
403	        if (!File.Exists(registryPath))
404	            return "WP-REGISTRY.json not found — WP 등록표가 없습니다";
405	
406	        var reg = JsonNode.Parse(File.ReadAllText(registryPath))?.AsObject();
407	        if (reg is null) return "WP-REGISTRY.json이 유효한 JSON 객체가 아닙니다";
408	
409	        var wps = reg["wps"] as JsonArray;
410	        if (wps is null) return "WP-REGISTRY.json에 'wps' 배열이 없습니다";
411	
412	        var exists = wps.OfType<JsonObject>().Any(w =>
413	            string.Equals(w["wpId"]?.ToString(), wpId, StringComparison.OrdinalIgnoreCase));
414	
415	        return exists ? null : $"wpId '{wpId}'가 WP-REGISTRY.json에 등록되지 않았습니다 — WP 추가는 사람 결재입니다";
416	    }
417	
418	    // CLI 인수를 파싱한다. 필수 인수(transition-id·expected-workstate-sha256·request)가 없으면 null 반환.
419	    // --root <경로>: 저장소 루트를 지정한다(사본 시험용). --dry-run: 검증만 하고 아무것도 쓰지 않는다.
420	    private static ApplierOptions? ParseArgs(string[] args)
421	    {
422	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
423	        var dryRun = false;
424	        for (var i = 1; i < args.Length; i++)
425	        {
426	            if (string.Equals(args[i], "--dry-run", StringComparison.OrdinalIgnoreCase))
427	            {
428	                dryRun = true;
429	                continue;
430	            }
431	            if (args[i].StartsWith("--", StringComparison.Ordinal) && i + 1 < args.Length)
432	            {
433	                map[args[i][2..]] = args[i + 1];
434	                i++;
435	            }
436	        }
437	
438	        if (!map.TryGetValue("transition-id", out var tid) || string.IsNullOrWhiteSpace(tid)) return null;
439	        if (!map.TryGetValue("expected-workstate-sha256", out var sha) || string.IsNullOrWhiteSpace(sha)) return null;
440	        if (!map.TryGetValue("request", out var req) || string.IsNullOrWhiteSpace(req)) return null;
441	
442	        map.TryGetValue("verdict", out var verdict);
443	        map.TryGetValue("human-decision", out var humanDec);
444	        map.TryGetValue("root", out var root);
445	        return new ApplierOptions(tid, sha, req, verdict, humanDec, root, dryRun);
446	    }
447	
448	    // appliedTransitions에서 transition-id 중복 여부를 확인한다.
449	    private static bool IsAlreadyApplied(JsonObject workstate, string transitionId)
450	    {
451	        var applied = workstate["appliedTransitions"] as JsonArray;
452	        if (applied is null) return false;
453	        return applied.OfType<JsonObject>().Any(o =>
454	            string.Equals(o["id"]?.ToString(), transitionId, StringComparison.OrdinalIgnoreCase));
455	    }
456	
457	    // 이미 적용된 transition-id에 대한 idempotent 응답을 출력하고 0을 반환한다.
458	    private static int ReportIdempotent(string transitionId)
459	    {
460	        Console.WriteLine(new JsonObject
461	        {
462	            ["ok"] = true,
463	            ["transitionId"] = transitionId,
464	            ["idempotent"] = true,
465	            ["note"] = "이 transition-id는 이미 적용됐다 — 상태를 바꾸지 않는다",
466	        }.ToJsonString(WriteOptions));
467	        return 0;
468	    }
469	
470	    // post-apply 단계 실패 메시지를 JSON 문자열로 만든다.
471	    private static string PostApplyError(string tid, string failure, int exitCode, bool wsApplied, bool projApplied)
472	    {
473	        var note = projApplied
474	            ? "WORKSTATE와 projection은 갱신됐으나 handoff-integrity가 실패했다"
475	            : "WORKSTATE는 갱신됐으나 projection이 실패했다 — projection을 수동으로 재실행하라";
476	        return new JsonObject
477	        {
478	            ["transitionId"] = tid,
479	            ["phase"] = "post-apply",
480	            ["failure"] = failure,
481	            ["exitCode"] = exitCode,
482	            ["workstateApplied"] = wsApplied,
483	            ["projectionApplied"] = projApplied,
484	            ["note"] = note,
485	        }.ToJsonString();
486	    }
487	
488	    // 전이 결과를 WORKSTATE.applier-log.jsonl에 한 줄 추가한다(append-only).
489	    private static void AppendApplierLog(string logPath, string transitionId, string result, int exitCode)
490	    {
491	        var entry = new JsonObject
492	        {
493	            ["transitionId"] = transitionId,
494	            ["result"] = result,
495	            ["exitCode"] = exitCode,
496	            ["at"] = DateTime.UtcNow.ToString("o"),
497	        };
498	        File.AppendAllText(logPath, entry.ToJsonString() + "\n", new UTF8Encoding(false));
499	    }
500	
501	    // stderr에 JSON 오류 메시지를 출력한다.
502	    private static void WriteError(string message)
503	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
504	
505	    // 실패 결과를 stderr에 출력하고 지정 exit code를 반환한다.
506	    private static int Fail(int exitCode, string transitionId, string reason, string detail)
507	    {
508	        Console.Error.WriteLine(new JsonObject
509	        {
510	            ["ok"] = false,
511	            ["transitionId"] = transitionId,
512	            ["reason"] = reason,
513	            ["detail"] = detail,
514	        }.ToJsonString());
515	        return exitCode;
516	    }
517	
518	    // 문자열의 SHA-256을 소문자 hex로 반환한다.
519	    private static string ComputeSha256(string content)
520	        => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(content))).ToLowerInvariant();
521	}
